from __future__ import annotations

import asyncio
from typing import Awaitable, Callable


async def run_tasks(tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int) -> None:
    """Run async jobs with bounded concurrency.

    If this coroutine is cancelled, for example due to a KeyboardInterrupt in
    the caller, any started jobs are cancelled and awaited so their try/finally
    cleanup blocks can run before re-raising.
    """
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    if not tasks:
        return

    queue: asyncio.Queue[Callable[[], Awaitable[None]]] = asyncio.Queue()
    for task in tasks:
        queue.put_nowait(task)

    async def worker() -> None:
        while True:
            try:
                task = queue.get_nowait()
            except asyncio.QueueEmpty:
                return

            try:
                await task()
            finally:
                queue.task_done()

    workers = [
        asyncio.create_task(worker())
        for _ in range(min(max_concurrent, len(tasks)))
    ]

    try:
        await asyncio.gather(*workers)
    except BaseException:
        current = asyncio.current_task()
        if current is not None:
            while current.cancelling() > 0:
                current.uncancel()

        for worker_task in workers:
            if not worker_task.done():
                worker_task.cancel()

        await asyncio.gather(*workers, return_exceptions=True)
        raise
